// MARK: - Transaction Processor
class TransactionProcessor {
    static let shared = TransactionProcessor()
    
    private init() {}
    
    func processTransaction(_ transaction: Transaction, from account: Account) -> Result<Account, TransactionError> {
        // Validate transaction
        guard validateTransaction(transaction, from: account) else {
            return .failure(.invalidTransaction)
        }
        
        // Process transaction
        let updatedAccount = updateAccountBalance(account, with: transaction)
        
        // Log transaction securely
        logTransactionSecurely(transaction)
        
        return .success(updatedAccount)
    }
    
    private func validateTransaction(_ transaction: Transaction, from account: Account) -> Bool {
        switch transaction.type {
        case .deposit:
            return transaction.amount > 0
        case .withdrawal, .transfer, .payment:
            return transaction.amount > 0 && transaction.amount <= account.balance
        }
    }
    
    private func updateAccountBalance(_ account: Account, with transaction: Transaction) -> Account {
        var updatedAccount = account
        switch transaction.type {
        case .deposit:
            updatedAccount.balance += transaction.amount
        case .withdrawal, .transfer, .payment:
            updatedAccount.balance -= transaction.amount
        }
        return updatedAccount
    }
    
