// MARK: - Secure Transaction View Controller
class SecureTransactionViewController: UIViewController {
    @IBOutlet weak var amountTextField: UITextField!
    @IBOutlet weak var descriptionTextField: UITextField!
    @IBOutlet weak var typeSegmentedControl: UISegmentedControl!
    @IBOutlet weak var submitButton: UIButton!
    
    private var selectedAccount: Account?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadSelectedAccount()
    }
    
    private func setupUI() {
        title = "New Transaction"
        view.backgroundColor = UIColor.systemBackground
        
        amountTextField.borderStyle = .roundedRect
        amountTextField.keyboardType = .decimalPad
        
        descriptionTextField.borderStyle = .roundedRect
        
        typeSegmentedControl.insertSegment(withTitle: "Deposit", at: 0, animated: false)
        typeSegmentedControl.insertSegment(withTitle: "Withdrawal", at: 1, animated: false)
        typeSegmentedControl.insertSegment(withTitle: "Transfer", at: 2, animated: false)
        typeSegmentedControl.selectedSegmentIndex = 0
        
        submitButton.backgroundColor = UIColor.systemBlue
        submitButton.setTitleColor(.white, for: .normal)
        submitButton.layer.cornerRadius = 8
    }
    
    private func loadSelectedAccount() {
        selectedAccount = SecureDataManager.shared.loadAccount(forKey: "current_account")
    }
    
    @IBAction func submitTransaction(_ sender: UIButton) {
        guard let amountText = amountTextField.text, let amount = Double(amountText),
              let description = descriptionTextField.text else {
            showAlert(message: "Please fill all fields")
            return
        }
        
        guard let account = selectedAccount else {
            showAlert(message: "No account selected")
            return
        }
        
        let transactionType: Transaction.TransactionType = {
            switch typeSegmentedControl.selectedSegmentIndex {
            case 0: return .deposit
            case 1: return .withdrawal
            case 2: return .transfer
            default: return .payment
            }
        }()
        
        let transaction = Transaction(
            id: UUID().uuidString,
            amount: amount,
            type: transactionType,
            date: Date(),
            description: description,
            recipient: nil
        )
        
        processTransaction(transaction, from: account)
    }
    
    private func processTransaction(_ transaction: Transaction, from account: Account) {
        TransactionProcessor.shared.processTransaction(transaction, from: account) { result in
            DispatchQueue.main.async {
                switch result {
                case .success(let updatedAccount):
                    self.handleSuccessfulTransaction(updatedAccount)
                case .failure(let error):
                    self.handleTransactionError(error)
                }
            }
        }
    }
    
    private func handleSuccessfulTransaction(_ account: Account) {
        SecureDataManager.shared.saveAccount(account, forKey: "current_account")
        showAlert(message: "Transaction completed successfully")
        resetForm()
    }
    
    private func handleTransactionError(_ error: TransactionError) {
        showAlert(message: error.localizedDescription)
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Transaction", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func resetForm() {
        amountTextField.text = ""
        descriptionTextField.text = ""
        typeSegmentedControl.selectedSegmentIndex = 0
    }
    
    private func validateTransaction(_ transaction: Transaction) -> Bool {
        return transaction.amount > 0 && !transaction.description.isEmpty
    }
}

